  font-size: var(--type-size-100);
  color: var(--color-text-secondary);
}
.bcn-obs__meta {
  font-size: var(--type-size-100);
  color: var(--color-text-tertiary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.bcn-obs__spacer {
  flex: 1 1 var(--spacing-300);
}
.cc-group + .cc-group {
  margin-top: var(--spacing-500);
}
.bcn-obs__badge {
  flex-shrink: 0;
